using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json.Serialization;
using ModelContextProtocol.Server;

namespace McpServer.Tools;

[McpServerToolType]
public sealed class WeatherTools
{
    private readonly HttpClient _httpClient;

    // Constructor injection — the MCP SDK resolves this from the DI container.
    public WeatherTools(HttpClient httpClient)
    {
        _httpClient = httpClient;
    }

    [McpServerTool, Description("Get current weather for a city.")]
    public async Task<string> GetCurrentWeather(
        [Description("City name, e.g. \"Seattle\"")] string city,
        CancellationToken cancellationToken = default)
    {
        var url = $"https://wttr.in/{Uri.EscapeDataString(city)}?format=j1";

        var response = await _httpClient.GetAsync(url, cancellationToken);
        if (!response.IsSuccessStatusCode)
            return $"Error: API returned {(int)response.StatusCode}";

        var data = await response.Content.ReadFromJsonAsync<WttrResponse>(cancellationToken);
        var current = data?.CurrentCondition?.FirstOrDefault();
        if (current is null)
            return "No weather data available.";

        return $"""
            Weather for {city}:
              Temperature: {current.TempC}°C / {current.TempF}°F
              Condition:   {current.WeatherDesc?.FirstOrDefault()?.Value ?? "Unknown"}
              Humidity:    {current.Humidity}%
              Wind:        {current.WindspeedKmph} km/h {current.WindDir}
            """;
    }

    [McpServerTool, Description("Get a short weather forecast for the next 3 days.")]
    public async Task<string> GetForecast(
        [Description("City name")] string city,
        CancellationToken cancellationToken = default)
    {
        var url = $"https://wttr.in/{Uri.EscapeDataString(city)}?format=j1";

        var response = await _httpClient.GetAsync(url, cancellationToken);
        if (!response.IsSuccessStatusCode)
            return $"Error: API returned {(int)response.StatusCode}";

        var data = await response.Content.ReadFromJsonAsync<WttrResponse>(cancellationToken);
        if (data?.Weather is null or { Count: 0 })
            return "No forecast data available.";

        var lines = data.Weather.Select(d =>
            $"  {d.Date}: {d.MaxTempC}°C / {d.MinTempC}°C");

        return $"3-day forecast for {city}:\n{string.Join('\n', lines)}";
    }
}

